180	// firstBalancedObject scans for the first '{' in s and returns the substring
181	// that closes its outermost JSON object, respecting strings and escapes.
182	// Returns ok=false on no opening brace or on an unterminated object.
183	func firstBalancedObject(s string) (string, bool) {
184		start := strings.Index(s, "{")
185		if start < 0 {
186			return "", false
187		}
188		depth := 0
189		inString := false
190		escape := false
191		for i := start; i < len(s); i++ {
192			c := s[i]
193			if escape {
194				escape = false
195				continue
196			}
197			if inString {
198				switch c {
199				case '\\':
200					escape = true
201				case '"':
202					inString = false
203				}
204				continue
205			}
206			switch c {
207			case '"':
208				inString = true
209			case '{':
210				depth++
211			case '}':
212				depth--
213				if depth == 0 {
214					return s[start : i+1], true
215				}
216			}
217		}
218		return "", false
219	}
