// TestBeadReviewProse_UsesNormalizedDocProseFindings verifies that the
// BuildReviewPromptWithProse path incorporates normalized docprose findings
// in the <prose-review> section of the review prompt. This covers AC#1:
// reuse of Vale-backed findings.
func TestBeadReviewProse_UsesNormalizedDocProseFindings(t *testing.T) {
	root := t.TempDir()

	// Set up a minimal .ddx directory with config so docprose can load settings.
	ddxDir := filepath.Join(root, ddxroot.DirName)
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))

	// Create a bead with prose that will trigger docprose findings.
	// This is generic AI-slop that the embedded checker should catch.
	b := &bead.Bead{
		ID:          "ddx-prose-1",
		Title:       "Test Prose Review",
		Description: "This robust system enables seamless workflow. It is important to note that comprehensive testing is critical.",
		Acceptance:  "AC#1: Verify findings are captured\nAC#2: Check findings are separate",
		Notes:       "Implement with powerful automation unlocking sophisticated capabilities.",
	}

	refs := []GoverningRef{}
	rev := "abc123"
	diff := "diff --git a/test.go b/test.go\n+// test change\n"

	// Call the prose-inclusive variant.
	result := BuildReviewPromptBounded(
		b, 1, rev, diff, root, refs,
		BuildReviewPromptOptions{Caps: evidence.DefaultCaps()},
	)

	prompt := result.Prompt

	// Assert the prose-review section is present and advisory.
	assert.Contains(t, prompt, "<prose-review advisory=\"true\">",
		"prose-review section must be marked advisory")

	// Assert findings are included in the prose section.
	assert.Contains(t, prompt, "<findings>",
		"prose-review must include a findings element")

	// Assert that docprose rule IDs appear (the normalized checker output).
	// Rule IDs follow the pattern prose.*.* from the docprose engine.
	// We expect at least one of the broad-claim or AI-slop rules to fire.
	hasProseRules := strings.Contains(prompt, "prose.") &&
		(strings.Contains(prompt, "prose.claim.unsupported") ||
			strings.Contains(prompt, "prose.ai_slop") ||
			strings.Contains(prompt, "prose.filler") ||
			strings.Contains(prompt, "prose.specificity") ||
			strings.Contains(prompt, "prose.cost") ||
			strings.Contains(prompt, "prose.structure."))
	assert.True(t, hasProseRules,
		"prompt must contain normalized docprose rule IDs (prose.* pattern) from Vale-backed checker")
}

// TestBeadReviewProse_EvidenceSeparateFromCorrectnessReview verifies that
// prose findings are attached separately from correctness-review evidence
// (the diff and AC-check sections) and that the ReviewVerdict JSON schema
// includes both findings and prose_findings fields. This covers AC#2.
func TestBeadReviewProse_EvidenceSeparateFromCorrectnessReview(t *testing.T) {
	root := t.TempDir()

	// Set up a minimal .ddx directory.
	ddxDir := filepath.Join(root, ddxroot.DirName)
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))

	b := &bead.Bead{
		ID:          "ddx-prose-2",
		Title:       "Prose and Correctness Separation",
		Description: "This enables powerful capabilities. The implementation adds two functions.",
		Acceptance:  "AC#1: Function A exists\nAC#2: Function B exists",
	}

	refs := []GoverningRef{}
	rev := "def456"
	diff := "diff --git a/impl.go b/impl.go\n" +
		"--- a/impl.go\n" +
		"+++ b/impl.go\n" +
		"@@ -1,0 +1,2 @@\n" +
		"+func A() {}\n" +
		"+func B() {}\n"

	// Build with prose.
	result := BuildReviewPromptBounded(
		b, 1, rev, diff, root, refs,
		BuildReviewPromptOptions{Caps: evidence.DefaultCaps()},
	)

	prompt := result.Prompt

	// Assert structure: <bead>, <diff>, <prose-review>, <instructions>.
	// Prose section must come after diff and before instructions.
	diffStart := strings.Index(prompt, "<diff")
	proseStart := strings.Index(prompt, "<prose-review")
	instructStart := strings.Index(prompt, "<instructions>")

	assert.Greater(t, diffStart, -1, "must have diff section")
	assert.Greater(t, proseStart, -1, "must have prose-review section")
	assert.Greater(t, instructStart, -1, "must have instructions section")
	assert.Less(t, diffStart, proseStart,
		"diff must come before prose-review")
	assert.Less(t, proseStart, instructStart,
		"prose-review must come before instructions")

	// Assert prose-review is in its own section.
	proseSection := prompt[proseStart:instructStart]
	assert.Contains(t, proseSection, "</prose-review>",
		"prose-review section must be properly closed")
	assert.NotContains(t, proseSection, "<findings>",
		"correctness findings go in correctness section, not prose-review; use <finding> within prose section")

	// Assert the instructions mention handling prose findings separately.
	instructionText := prompt[instructStart:]
	assert.Contains(t, instructionText, "prose_findings",
		"instructions must tell reviewer to include prose_findings in output")
	assert.Contains(t, instructionText, "Keep prose findings separate",
		"instructions must emphasize separation")
	assert.Contains(t, instructionText, "advisory",
		"instructions must state prose findings are advisory")

	// Test that a reviewer's JSON response with both findings and prose_findings
	// parses correctly (separateness in the schema).
	reviewerOutput := `
{
  "schema_version": 1,
  "verdict": "APPROVE",
  "summary": "Both AC items met",
  "per_ac": [
    {"number": 1, "item": "Function A exists", "grade": "pass", "evidence": "impl.go:1"},
    {"number": 2, "item": "Function B exists", "grade": "pass", "evidence": "impl.go:2"}
  ],
  "findings": [
    {"severity": "info", "summary": "Good implementation structure", "location": "impl.go:1"}
  ],
  "prose_findings": [
    {"severity": "info", "summary": "Broad claim: 'powerful capabilities' needs specificity", "location": "bead:description"}
  ]
}
` + "```"

	parsed, err := ParseReviewVerdict([]byte(reviewerOutput))
	require.NoError(t, err, "reviewer verdict with both findings and prose_findings must parse")
	assert.Equal(t, VerdictApprove, parsed.Verdict)
	assert.Len(t, parsed.Findings, 1, "correctness findings present")
	assert.Len(t, parsed.ProseFindings, 1, "prose findings present")
	assert.NotEqual(t, parsed.Findings, parsed.ProseFindings,
		"findings and prose_findings must be separate fields")
}

// TestBeadReviewProse_AdvisoryByDefault verifies that prose findings do not
// block bead closure and that a verdict of APPROVE can coexist with prose
// findings without the verdict changing. This covers AC#3.
func TestBeadReviewProse_AdvisoryByDefault(t *testing.T) {
	root := t.TempDir()

	// Set up .ddx directory.
	ddxDir := filepath.Join(root, ddxroot.DirName)
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))

	// Create a bead with both correctness and prose issues.
	b := &bead.Bead{
		ID:          "ddx-prose-3",
		Title:       "Advisory Prose Test",
		Description: "This provides comprehensive enablement of workflow capabilities through robust automation.",
		Acceptance:  "AC#1: Implement handler\nAC#2: Add tests",
	}

	refs := []GoverningRef{}
	rev := "ghi789"
	diff := "diff --git a/handler.go b/handler.go\n" +
		"--- a/handler.go\n" +
		"+++ b/handler.go\n" +
		"@@ -1,0 +1,5 @@\n" +
		"+func Handle(r *http.Request) {\n" +
		"+  // process request\n" +
		"+}\n" +
		"diff --git a/handler_test.go b/handler_test.go\n" +
		"--- a/handler_test.go\n" +
		"+++ b/handler_test.go\n" +
		"@@ -1,0 +1,10 @@\n" +
		"+func TestHandle(t *testing.T) {\n" +
		"+  // test cases\n" +
		"+}\n"

	// Build the prompt with prose.
	result := BuildReviewPromptBounded(
		b, 1, rev, diff, root, refs,
		BuildReviewPromptOptions{Caps: evidence.DefaultCaps()},
	)

	prompt := result.Prompt

	// Assert prose-review is present.
	assert.Contains(t, prompt, "<prose-review advisory=\"true\">")

	// Simulate a reviewer response: APPROVE verdict with prose findings present.
	// The key point: prose findings do NOT change the verdict from APPROVE to
	// something else; they remain advisory.
	reviewerOutput := `
{
  "schema_version": 1,
  "verdict": "APPROVE",
  "summary": "Both AC items fully implemented",
  "per_ac": [
    {"number": 1, "item": "Implement handler", "grade": "pass", "evidence": "handler.go:1 func Handle"},
    {"number": 2, "item": "Add tests", "grade": "pass", "evidence": "handler_test.go:1 func TestHandle"}
  ],
  "findings": [],
  "prose_findings": [
    {"severity": "info", "summary": "Broad claim without specificity", "location": "bead.md:2"},
    {"severity": "info", "summary": "Filler transition", "location": "bead.md:2"}
  ]
}
` + "```"

	parsed, err := ParseReviewVerdict([]byte(reviewerOutput))
	require.NoError(t, err)

	// Key assertions: APPROVE verdict persists despite prose findings.
	assert.Equal(t, VerdictApprove, parsed.Verdict,
		"APPROVE verdict must not be downgraded by presence of prose findings")
	assert.Len(t, parsed.ProseFindings, 2,
		"prose findings are captured in the output")
	assert.NotEmpty(t, parsed.ProseFindings[0].Summary,
		"prose findings include rationale")

	// Build ReviewResult from parsed verdict (simulating what reviewBeadWithDiff does).
	reviewResult := &ReviewResult{
		Verdict:       parsed.Verdict,
		Rationale:     strings.TrimSpace(parsed.Summary),
		PerAC:         parsed.PerAC,
		Findings:      parsed.Findings,
		ProseFindings: parsed.ProseFindings,
	}

	// Assert the result preserves the advisory nature.
	assert.Equal(t, VerdictApprove, reviewResult.Verdict,
		"ReviewResult verdict is APPROVE; prose findings are stored separately")
	assert.NotEmpty(t, reviewResult.ProseFindings,
		"prose findings are preserved in ReviewResult")
	assert.Empty(t, reviewResult.Findings,
		"no correctness findings in this case")

	// Assert that prose findings would not trigger a closure block.
	// In the work loop, the closure decision is driven by Verdict, not
	// ProseFindings. A reviewer returning APPROVE + prose_findings means
	// the bead closes despite the prose issues (since prose is advisory).
	shouldClose := reviewResult.Verdict == VerdictApprove
	assert.True(t, shouldClose,
		"bead should close (verdict is APPROVE) even with prose findings present")
}

